import React, { useState, useEffect } from 'react';
import './billing.css';

const Billing = () => {
    const [invoices, setInvoices] = useState([]);
    const [searchQuery, setSearchQuery] = useState('');

    // 1. Fetch Invoices from Backend
    const fetchInvoices = async () => {
        try {
            const response = await fetch('http://localhost:5000/api/billing');
            const data = await response.json();
            setInvoices(data);
        } catch (error) {
            console.error("Error fetching billing data:", error);
        }
    };

    useEffect(() => {
        fetchInvoices();
    }, []);

    // 2. Dynamic Calculations for Summary Boxes
    const totalIncome = invoices
        .filter(inv => inv.status === 'Paid')
        .reduce((sum, inv) => sum + (parseFloat(inv.amount) || 0), 0);

    const outstandingBalance = invoices
        .filter(inv => inv.status !== 'Paid')
        .reduce((sum, inv) => sum + (parseFloat(inv.amount) || 0), 0);

    // 3. Filtered Search Logic
    const filteredInvoices = invoices.filter(inv => 
        inv.patientName?.toLowerCase().includes(searchQuery.toLowerCase()) ||
        inv.invoiceNumber?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div className="billing-page">
            <div className="billing-header">
                <div>
                    <h1>Billing & Invoices</h1>
                    <p>Track payments, insurance claims, and hospital revenue.</p>
                </div>
                <button className="generate-btn">📄 Generate New Invoice</button>
            </div>

            {/* Financial Summary Row - Now Dynamic */}
            <div className="billing-stats">
                <div className="stat-box income">
                    <span>Total Income</span>
                    <h3>${totalIncome.toLocaleString(undefined, { minimumFractionDigits: 2 })}</h3>
                </div>
                <div className="stat-box pending">
                    <span>Outstanding</span>
                    <h3>${outstandingBalance.toLocaleString(undefined, { minimumFractionDigits: 2 })}</h3>
                </div>
            </div>

            <div className="invoice-table-container">
                <div className="table-top">
                    <h3>Recent Invoices</h3>
                    <input 
                        type="text" 
                        placeholder="Search Invoice ID or Patient..." 
                        className="bill-search"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
                
                <table className="billing-table">
                    <thead>
                        <tr>
                            <th>Invoice ID</th>
                            <th>Patient</th>
                            <th>Date</th>
                            <th>Amount</th>
                            <th>Status</th>
                            <th>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredInvoices.length > 0 ? filteredInvoices.map((inv) => (
                            <tr key={inv._id}>
                                <td className="inv-id">#{inv.invoiceNumber}</td>
                                <td className="inv-patient">{inv.patientName}</td>
                                <td>{new Date(inv.date).toLocaleDateString()}</td>
                                <td className="inv-amount">${inv.amount}</td>
                                <td>
                                    <span className={`pay-status ${inv.status.toLowerCase()}`}>
                                        {inv.status}
                                    </span>
                                </td>
                                <td>
                                    <button className="print-btn" onClick={() => window.print()}>Print</button>
                                </td>
                            </tr>
                        )) : (
                            <tr><td colSpan="6" style={{textAlign: 'center', padding: '20px'}}>No records found.</td></tr>
                        )}
                    </tbody>
                </table>
            </div>
        </div>
    );
};

export default Billing;
